INSERT INTO avatar_definitions (code, title, description, rarity, points_bonus, image_lg, image_md, image_sm, unlock_label, unlock_requirement, sort_order) VALUES
('avatar_001', 'Caballero del Eclipse Carmesí', 'Guardián de un ocaso eterno cuya espada de plasma escarlata corta el silencio de las ciudades dormidas. Solo se entrega a quien aprende a luchar sin perder la calma.', 'epic', 0.3, '/images/avatar/512/avatar-001.webp', '/images/avatar/256/avatar-001.webp', '/images/avatar/128/avatar-001.webp', 'Alcanza el nivel 15', '{"type": "level", "value": 15}'::jsonb, 1),
('avatar_002', 'Maestro del Ajedrez Nocturno', 'Estratega de mente fría que mueve las piezas como mueve las palabras: con precisión y elegancia. Cada lectura suya es una jugada maestra.', 'epic', 0.3, '/images/avatar/512/avatar-002.webp', '/images/avatar/256/avatar-002.webp', '/images/avatar/128/avatar-002.webp', 'Aprueba 10 exámenes con nota ≥ 8.5', '{"type": "high_score_exams", "count": 10, "min_nota": 8.5}'::jsonb, 2),
('avatar_003', 'Titán Rúnico', 'Coloso púrpura cubierto de glifos antiguos. Su fuerza nace de los símbolos: aprender una nueva palabra le hace un poco más invencible.', 'legendary', 0.4, '/images/avatar/512/avatar-003.webp', '/images/avatar/256/avatar-003.webp', '/images/avatar/128/avatar-003.webp', 'Alcanza el nivel 25', '{"type": "level", "value": 25}'::jsonb, 3),
('avatar_004', 'Lord Sombra del Imperio', 'Ningún duelo se le resiste. Habla poco, observa todo y golpea cuando el rival baja la guardia.', 'epic', 0.3, '/images/avatar/512/avatar-004.webp', '/images/avatar/256/avatar-004.webp', '/images/avatar/128/avatar-004.webp', 'Gana 10 duelos', '{"type": "duels_won", "count": 10}'::jsonb, 4),
('avatar_005', 'Detective Filósofo', 'Ningún acertijo se le escapa. Combina lógica de novela negra con la calma del que ya ha leído todos los libros.', 'rare', 0.2, '/images/avatar/512/avatar-005.webp', '/images/avatar/256/avatar-005.webp', '/images/avatar/128/avatar-005.webp', 'Aprueba 3 exámenes del Rosco del Saber', '{"type": "app_sessions", "app_id": "rosco-del-saber", "mode": "test", "count": 3, "min_nota": 7}'::jsonb, 5),
('avatar_006', 'Necromante de las Sombras', 'Invoca palabras perdidas y letras olvidadas. Domina el Ahorcado como nadie: las letras simplemente acuden a él.', 'epic', 0.3, '/images/avatar/512/avatar-006.webp', '/images/avatar/256/avatar-006.webp', '/images/avatar/128/avatar-006.webp', 'Aprueba 7 exámenes de Ahorcado con nota ≥ 8', '{"type": "app_sessions", "app_id": "ahorcado", "mode": "test", "count": 7, "min_nota": 8}'::jsonb, 6),
('avatar_007', 'Hechicero Cristalino', 'Sus cristales guardan recuerdos y fórmulas. Una mirada suya y los problemas más difíciles se vuelven luz.', 'legendary', 0.4, '/images/avatar/512/avatar-007.webp', '/images/avatar/256/avatar-007.webp', '/images/avatar/128/avatar-007.webp', 'Consigue 15 exámenes con nota perfecta (10)', '{"type": "perfect_exams", "count": 15}'::jsonb, 7),
('avatar_008', 'Programador Alquimista', 'Mezcla letras como reactivos y crea palabras nuevas en su laboratorio. Los Anagramas no tienen secretos para él.', 'rare', 0.2, '/images/avatar/512/avatar-008.webp', '/images/avatar/256/avatar-008.webp', '/images/avatar/128/avatar-008.webp', 'Aprueba 3 exámenes de Anagramas', '{"type": "app_sessions", "app_id": "anagramas", "mode": "test", "count": 3, "min_nota": 7}'::jsonb, 8),
('avatar_009', 'Capitana del Debate', 'Convence con argumentos y entusiasmo. Defiende sus ideas como un escudo, escucha como un detective y responde como una abogada.', 'rare', 0.2, '/images/avatar/512/avatar-009.webp', '/images/avatar/256/avatar-009.webp', '/images/avatar/128/avatar-009.webp', 'Aprueba 3 exámenes de Comprensión Escrita', '{"type": "app_sessions", "app_id": "comprension-escrita", "mode": "test", "count": 3, "min_nota": 7}'::jsonb, 9),
('avatar_010', 'Cronista del Tiempo', 'Viaja entre épocas con su pergamino brillante. Sabe que la historia se repite, pero la cuenta siempre con voz nueva.', 'rare', 0.2, '/images/avatar/512/avatar-010.webp', '/images/avatar/256/avatar-010.webp', '/images/avatar/128/avatar-010.webp', 'Aprueba 5 exámenes de Personajes Históricos', '{"type": "app_sessions", "app_id": "generador-personajes-historicos", "count": 5}'::jsonb, 10),
('avatar_011', 'Ingeniera Robótica', 'Construye, prueba, mejora. Cuando otros ven un cable suelto, ella ve un robot esperando a nacer.', 'rare', 0.2, '/images/avatar/512/avatar-011.webp', '/images/avatar/256/avatar-011.webp', '/images/avatar/128/avatar-011.webp', 'Completa 5 misiones del Laboratorio de Robótica', '{"type": "app_sessions", "app_id": "laboratorio-robotica", "count": 5}'::jsonb, 11),
('avatar_012', 'Piloto de Drones', 'Marca una ruta en el mapa y la vuela con los ojos cerrados. Si hay un objetivo, hay un trayecto, y él lo ejecuta.', 'rare', 0.2, '/images/avatar/512/avatar-012.webp', '/images/avatar/256/avatar-012.webp', '/images/avatar/128/avatar-012.webp', 'Completa 5 misiones de Programación por Bloques', '{"type": "app_sessions", "app_id": "programacion-bloques", "count": 5}'::jsonb, 12),
('avatar_013', 'Guardián del Saber', 'Sostiene el libro y la llave: el conocimiento abre puertas y a la vez las protege. Solo entrega su título a quien lee mucho.', 'epic', 0.3, '/images/avatar/512/avatar-013.webp', '/images/avatar/256/avatar-013.webp', '/images/avatar/128/avatar-013.webp', 'Aprueba 10 exámenes con nota ≥ 8 en Lengua', '{"type": "subject_exams", "subject_id": "lengua", "count": 10, "min_nota": 8}'::jsonb, 13),
('avatar_014', 'Maestra de las Matemáticas', 'Resuelve mientras todos miran. Su superpoder no es la velocidad: es no equivocarse.', 'rare', 0.2, '/images/avatar/512/avatar-014.webp', '/images/avatar/256/avatar-014.webp', '/images/avatar/128/avatar-014.webp', 'Aprueba 3 exámenes de Regla de Tres con nota ≥ 8', '{"type": "app_sessions", "app_id": "regla-de-tres", "mode": "test", "count": 3, "min_nota": 8}'::jsonb, 14),
('avatar_015', 'Arquitecto de Mundos', 'Construye ciudades de bloques en su mente y luego las ordena en el papel. Diseñar es su forma de pensar.', 'rare', 0.2, '/images/avatar/512/avatar-015.webp', '/images/avatar/256/avatar-015.webp', '/images/avatar/128/avatar-015.webp', 'Completa 3 sesiones de Mesa de Crafteo', '{"type": "app_sessions", "app_id": "mesa-crafteo", "count": 3}'::jsonb, 15),
('avatar_016', 'Naturalista de Campo', 'Microscopio en una mano, cuaderno en la otra. Mira un río y ve cien historias.', 'rare', 0.2, '/images/avatar/512/avatar-016.webp', '/images/avatar/256/avatar-016.webp', '/images/avatar/128/avatar-016.webp', 'Aprueba 3 exámenes de Excavación Selectiva', '{"type": "app_sessions", "app_id": "excavacion-selectiva", "mode": "test", "count": 3}'::jsonb, 16),
('avatar_017', 'Hacker Ético', 'Cazaerrores y cazatrampas. Si hay un patrón roto, lo encuentra y lo arregla con una sonrisa silenciosa.', 'rare', 0.2, '/images/avatar/512/avatar-017.webp', '/images/avatar/256/avatar-017.webp', '/images/avatar/128/avatar-017.webp', 'Alcanza el nivel 5', '{"type": "level", "value": 5}'::jsonb, 17),
('avatar_018', 'Vikingo Montañés', 'Subió la montaña con un pico. Bajó con palabras nuevas que nadie había escrito todavía.', 'epic', 0.3, '/images/avatar/512/avatar-018.webp', '/images/avatar/256/avatar-018.webp', '/images/avatar/128/avatar-018.webp', 'Gana 7 batallas', '{"type": "battles_won", "count": 7}'::jsonb, 18),
('avatar_019', 'Atleta del Mar', 'Nada contra cualquier corriente. Cuando empieza a cronometrar, el resto del mundo se queda en silencio.', 'rare', 0.2, '/images/avatar/512/avatar-019.webp', '/images/avatar/256/avatar-019.webp', '/images/avatar/128/avatar-019.webp', 'Gana 3 batallas', '{"type": "battles_won", "count": 3}'::jsonb, 19),
('avatar_020', 'Herrero Forjador', 'Golpe a golpe convierte el hierro en arte. Las palabras también: cada respuesta correcta es un martillazo certero.', 'rare', 0.2, '/images/avatar/512/avatar-020.webp', '/images/avatar/256/avatar-020.webp', '/images/avatar/128/avatar-020.webp', 'Aprueba 5 exámenes de Velocidad de Respuesta', '{"type": "app_sessions", "app_id": "velocidad-respuesta", "mode": "test", "count": 5}'::jsonb, 20),
('avatar_021', 'Guerrera del Dragón Rojo', 'Cabalga al lado de los dragones porque entendió primero su lengua. La furia, dice, también se aprende.', 'epic', 0.3, '/images/avatar/512/avatar-021.webp', '/images/avatar/256/avatar-021.webp', '/images/avatar/128/avatar-021.webp', 'Alcanza el nivel 18', '{"type": "level", "value": 18}'::jsonb, 21),
('avatar_022', 'Capitán de Rugby', 'Se ensucia primero, mira a sus compañeros, levanta la cabeza y va. Los duelos son su terreno favorito.', 'rare', 0.2, '/images/avatar/512/avatar-022.webp', '/images/avatar/256/avatar-022.webp', '/images/avatar/128/avatar-022.webp', 'Gana 3 duelos', '{"type": "duels_won", "count": 3}'::jsonb, 22),
('avatar_023', 'Boxeadora Indomable', 'No excusas, sólo impacto. Los duelos no la cansan: la afilan.', 'rare', 0.2, '/images/avatar/512/avatar-023.webp', '/images/avatar/256/avatar-023.webp', '/images/avatar/128/avatar-023.webp', 'Gana 5 duelos', '{"type": "duels_won", "count": 5}'::jsonb, 23),
('avatar_024', 'Minero de Cristales', 'Pico al hombro y luz en la frente. Nunca vuelve sin algo brillante: una idea, una palabra, una respuesta.', 'rare', 0.2, '/images/avatar/512/avatar-024.webp', '/images/avatar/256/avatar-024.webp', '/images/avatar/128/avatar-024.webp', 'Completa 5 sesiones de Excavación Selectiva', '{"type": "app_sessions", "app_id": "excavacion-selectiva", "count": 5}'::jsonb, 24),
('avatar_025', 'Guerrera Solar', 'Luchó por su pueblo bajo el sol del desierto. La historia la recuerda con lanza dorada y mirada serena.', 'epic', 0.3, '/images/avatar/512/avatar-025.webp', '/images/avatar/256/avatar-025.webp', '/images/avatar/128/avatar-025.webp', 'Aprueba 10 exámenes de Sociales con nota ≥ 8', '{"type": "subject_exams", "subject_id": "sociales", "count": 10, "min_nota": 8}'::jsonb, 25),
('avatar_026', 'Bombero Heroico', 'Donde otros huyen, él entra. La constancia es su mejor herramienta: el día que falte uno, faltarán todos.', 'rare', 0.2, '/images/avatar/512/avatar-026.webp', '/images/avatar/256/avatar-026.webp', '/images/avatar/128/avatar-026.webp', 'Mantén una racha de 7 días jugando', '{"type": "streak_days", "count": 7}'::jsonb, 26),
('avatar_027', 'Reina Vikinga', 'Lidera con hacha, escudo y libro. Sabe que conquistar también es enseñar.', 'epic', 0.3, '/images/avatar/512/avatar-027.webp', '/images/avatar/256/avatar-027.webp', '/images/avatar/128/avatar-027.webp', 'Entra en el top 3 de tu clase', '{"type": "top_class", "position": 3}'::jsonb, 27),
('avatar_028', 'Atleta de Hierro', 'Levanta lo que otros ni miran. Su récord no es el peso: es la cantidad de veces que ha vuelto al gimnasio.', 'rare', 0.2, '/images/avatar/512/avatar-028.webp', '/images/avatar/256/avatar-028.webp', '/images/avatar/128/avatar-028.webp', 'Aprueba 10 exámenes con nota ≥ 7', '{"type": "high_score_exams", "count": 10, "min_nota": 7}'::jsonb, 28),
('avatar_029', 'Gladiador Imperial', 'Pisó la arena cien veces y salió cien veces. Los duelos no son su trabajo: son su poesía.', 'epic', 0.3, '/images/avatar/512/avatar-029.webp', '/images/avatar/256/avatar-029.webp', '/images/avatar/128/avatar-029.webp', 'Gana 15 duelos', '{"type": "duels_won", "count": 15}'::jsonb, 29),
('avatar_030', 'Astrónoma del Zodíaco', 'Lee el cielo como otros leen un cuento. Cuando hay luna nueva, ella escribe el siguiente capítulo.', 'rare', 0.2, '/images/avatar/512/avatar-030.webp', '/images/avatar/256/avatar-030.webp', '/images/avatar/128/avatar-030.webp', 'Completa 5 sesiones del Sistema Solar', '{"type": "app_sessions", "app_id": "sistema-solar", "count": 5}'::jsonb, 30),
('avatar_031', 'Robot Estudiante', 'Acaba de encenderse y ya quiere aprender. Si aciertas, sus ojos brillan; si fallas, te invita a intentarlo otra vez.', 'common', 0.1, '/images/avatar/512/avatar-031.webp', '/images/avatar/256/avatar-031.webp', '/images/avatar/128/avatar-031.webp', 'Completa tu primera partida', '{"type": "total_sessions", "count": 1}'::jsonb, 31),
('avatar_032', 'Cadete Espacial', 'Recién salido de la academia, pero ya sueña con la próxima galaxia. La curiosidad es su combustible.', 'rare', 0.2, '/images/avatar/512/avatar-032.webp', '/images/avatar/256/avatar-032.webp', '/images/avatar/128/avatar-032.webp', 'Aprueba 5 exámenes del Sistema Solar', '{"type": "app_sessions", "app_id": "sistema-solar", "mode": "test", "count": 5}'::jsonb, 32),
('avatar_033', 'Ninja del Estudio', 'Estudia en silencio, ataca con A+. Llega antes de que los demás abran el cuaderno.', 'rare', 0.2, '/images/avatar/512/avatar-033.webp', '/images/avatar/256/avatar-033.webp', '/images/avatar/128/avatar-033.webp', 'Alcanza el nivel 8', '{"type": "level", "value": 8}'::jsonb, 33),
('avatar_034', 'Detective de Datos', 'Un patrón, una pista, una respuesta. Las palabras son su lupa.', 'rare', 0.2, '/images/avatar/512/avatar-034.webp', '/images/avatar/256/avatar-034.webp', '/images/avatar/128/avatar-034.webp', 'Aprueba 5 exámenes de Detective de Palabras', '{"type": "app_sessions", "app_id": "detective-de-palabras", "mode": "test", "count": 5}'::jsonb, 34),
('avatar_035', 'Ingeniero Inventor', 'Tiene un cuaderno lleno de planos y un robot mascota que aplaude cuando aprueba.', 'rare', 0.2, '/images/avatar/512/avatar-035.webp', '/images/avatar/256/avatar-035.webp', '/images/avatar/128/avatar-035.webp', 'Completa 10 misiones de Robótica', '{"type": "app_sessions", "app_id": "misiones-roboticas", "count": 10}'::jsonb, 35),
('avatar_036', 'Goblin del Cristal', 'Pequeño, escurridizo y con un cristal precioso entre las manos. Los misterios brillan donde él pasa.', 'epic', 0.3, '/images/avatar/512/avatar-036.webp', '/images/avatar/256/avatar-036.webp', '/images/avatar/128/avatar-036.webp', 'Aprueba 10 exámenes de Memoria', '{"type": "app_sessions", "app_id": "juego-memoria", "mode": "test", "count": 10}'::jsonb, 36),
('avatar_037', 'Señor Oscuro', 'Su corona pesa porque cargó con muchas batallas. No pierde jamás un duelo: ni siquiera cuando le toca callar.', 'legendary', 0.4, '/images/avatar/512/avatar-037.webp', '/images/avatar/256/avatar-037.webp', '/images/avatar/128/avatar-037.webp', 'Gana 30 duelos', '{"type": "duels_won", "count": 30}'::jsonb, 37),
('avatar_038', 'Druida del Bosque', 'Habla con los árboles, conoce las plantas y respeta las raíces. La naturaleza le abrió la puerta hace tiempo.', 'epic', 0.3, '/images/avatar/512/avatar-038.webp', '/images/avatar/256/avatar-038.webp', '/images/avatar/128/avatar-038.webp', 'Aprueba 10 exámenes de Naturales con nota ≥ 8', '{"type": "subject_exams", "subject_id": "naturales", "count": 10, "min_nota": 8}'::jsonb, 38),
('avatar_039', 'Matemático Cósmico', 'Cuando mira el cielo, ve ecuaciones. Cuando mira ecuaciones, ve un poco de cielo.', 'epic', 0.3, '/images/avatar/512/avatar-039.webp', '/images/avatar/256/avatar-039.webp', '/images/avatar/128/avatar-039.webp', 'Aprueba 15 exámenes de Matemáticas con nota ≥ 8', '{"type": "subject_exams", "subject_id": "matematicas", "count": 15, "min_nota": 8}'::jsonb, 39),
('avatar_040', 'Corredor Urbano', 'Salta vallas y atraviesa azoteas como si fueran problemas: con velocidad y agilidad.', 'rare', 0.2, '/images/avatar/512/avatar-040.webp', '/images/avatar/256/avatar-040.webp', '/images/avatar/128/avatar-040.webp', 'Aprueba 5 exámenes de Velocidad de Respuesta', '{"type": "app_sessions", "app_id": "velocidad-respuesta", "mode": "test", "count": 5, "min_nota": 7}'::jsonb, 40),
('avatar_041', 'Dios del Trueno', 'Levanta el martillo y el aula entera escucha. Cuando aprueba, las paredes vibran.', 'legendary', 0.4, '/images/avatar/512/avatar-041.webp', '/images/avatar/256/avatar-041.webp', '/images/avatar/128/avatar-041.webp', 'Alcanza el nivel 30', '{"type": "level", "value": 30}'::jsonb, 41),
('avatar_042', 'Bufón del Caos', 'Trickster, mago, mente curiosa: confunde a los rivales con tres movimientos y gana con el cuarto.', 'epic', 0.3, '/images/avatar/512/avatar-042.webp', '/images/avatar/256/avatar-042.webp', '/images/avatar/128/avatar-042.webp', 'Termina en podio en 10 batallas', '{"type": "battles_won", "count": 10}'::jsonb, 42),
('avatar_043', 'Inventor Cibernético', 'Su traje brilla cada vez que aprende algo nuevo. Está lleno de luces; está lleno de respuestas.', 'rare', 0.2, '/images/avatar/512/avatar-043.webp', '/images/avatar/256/avatar-043.webp', '/images/avatar/128/avatar-043.webp', 'Juega al menos 8 apps distintas', '{"type": "unique_apps", "count": 8}'::jsonb, 43),
('avatar_044', 'Leyenda del Rock', 'Sale al escenario y nadie quiere ver otra cosa. Convierte cada respuesta en un coro inolvidable.', 'legendary', 0.4, '/images/avatar/512/avatar-044.webp', '/images/avatar/256/avatar-044.webp', '/images/avatar/128/avatar-044.webp', 'Desbloquea 30 insignias', '{"type": "badges_count", "count": 30}'::jsonb, 44),
('avatar_045', 'Mamba Negra', 'Trabaja antes que nadie y se queda después que todos. Mentalidad: la tarea no se acaba hasta que está perfecta.', 'legendary', 0.4, '/images/avatar/512/avatar-045.webp', '/images/avatar/256/avatar-045.webp', '/images/avatar/128/avatar-045.webp', 'Gana 25 batallas', '{"type": "battles_won", "count": 25}'::jsonb, 45),
('avatar_046', 'Su Majestad del Aire', 'Vuela donde nadie más llega. Cuando hay un partido decisivo, todos miran hacia arriba para encontrarlo.', 'mythic', 0.5, '/images/avatar/512/avatar-046.webp', '/images/avatar/256/avatar-046.webp', '/images/avatar/128/avatar-046.webp', 'Gana 50 batallas', '{"type": "battles_won", "count": 50}'::jsonb, 46),
('avatar_047', 'El Comandante', 'Su número favorito es 7 y no falla un tiro. Lidera por ejemplo, no por gritos.', 'legendary', 0.4, '/images/avatar/512/avatar-047.webp', '/images/avatar/256/avatar-047.webp', '/images/avatar/128/avatar-047.webp', 'Gana 30 duelos en racha', '{"type": "duels_won", "count": 30}'::jsonb, 47),
('avatar_048', 'El Pulga Mágico', 'Pequeño, zurdo, imparable. La pelota se le pega al pie, las respuestas se le pegan a la mente.', 'mythic', 0.5, '/images/avatar/512/avatar-048.webp', '/images/avatar/256/avatar-048.webp', '/images/avatar/128/avatar-048.webp', 'Alcanza el #1 del ranking de tu clase', '{"type": "top_class", "position": 1}'::jsonb, 48),
('avatar_049', 'Padre de la Computación', 'Descifró un código que cambió la guerra. Aún hoy, las matemáticas le hacen reverencias.', 'epic', 0.3, '/images/avatar/512/avatar-049.webp', '/images/avatar/256/avatar-049.webp', '/images/avatar/128/avatar-049.webp', 'Aprueba 10 exámenes de Matemáticas con nota ≥ 9', '{"type": "subject_exams", "subject_id": "matematicas", "count": 10, "min_nota": 9}'::jsonb, 49),
('avatar_050', 'Astrónomo Pionero', 'Apuntó al cielo cuando nadie le creía. Hoy, cada estrella lleva un poco de su nombre.', 'legendary', 0.4, '/images/avatar/512/avatar-050.webp', '/images/avatar/256/avatar-050.webp', '/images/avatar/128/avatar-050.webp', 'Aprueba 15 exámenes del Sistema Solar con nota perfecta', '{"type": "app_sessions", "app_id": "sistema-solar", "mode": "test", "count": 15, "min_nota": 9.5}'::jsonb, 50),
('avatar_051', 'Reina del Nilo', 'Habla siete idiomas y reina sobre el desierto. Cada palabra suya es una pirámide.', 'legendary', 0.4, '/images/avatar/512/avatar-051.webp', '/images/avatar/256/avatar-051.webp', '/images/avatar/128/avatar-051.webp', 'Alcanza el #1 global de la plataforma', '{"type": "top_global", "position": 1}'::jsonb, 51),
('avatar_052', 'Genio del Renacimiento', 'Pinta, escribe, inventa, vuela. Si una cosa tiene engranajes, él los entiende; si tiene alma, también.', 'mythic', 0.5, '/images/avatar/512/avatar-052.webp', '/images/avatar/256/avatar-052.webp', '/images/avatar/128/avatar-052.webp', 'Desbloquea 80 insignias', '{"type": "badges_count", "count": 80}'::jsonb, 52),
('avatar_053', 'Maestro del Rayo', 'Convirtió la electricidad en magia útil. Sus ideas todavía iluminan ciudades.', 'legendary', 0.4, '/images/avatar/512/avatar-053.webp', '/images/avatar/256/avatar-053.webp', '/images/avatar/128/avatar-053.webp', 'Aprueba 20 exámenes con nota ≥ 9', '{"type": "high_score_exams", "count": 20, "min_nota": 9}'::jsonb, 53),
('avatar_054', 'Padre de la Física', 'Vio caer una manzana y cambió el universo. Sus leyes te siguen aunque no lo sepas.', 'legendary', 0.4, '/images/avatar/512/avatar-054.webp', '/images/avatar/256/avatar-054.webp', '/images/avatar/128/avatar-054.webp', 'Aprueba 20 exámenes de Matemáticas con nota ≥ 9.5', '{"type": "subject_exams", "subject_id": "matematicas", "count": 20, "min_nota": 9.5}'::jsonb, 54),
